#include <bits/stdc++.h>
using namespace std;

int main(){
    int n, x;
    cin >> n >> x;

    int A[n + 1];

    // Using one-based indexing
    for(int i = 1; i <= n; i++) {
        cin >> A[i];
    }   

    // We will use 2-d array to store the solution 
    int dp[n + 1][x + 1];

    for(int i = 0; i <= n; i++) {
        // Base case, can make sum = 0 alwaus
        dp[i][0] = 1; 
    }
    for(int j = 1; j <= x; j++) {
        // Base case, can never make any sum with no elements
        dp[0][j] = 0; 
    }   

    for(int i = 1; i <= n; i++) {
        for(int j = 1; j <= x; j++) {
            if(j >= A[i]) {
                // Either can be true
                dp[i][j] = dp[i - 1][j] | dp[i - 1][j - A[i]];
            }
            else {
                dp[i][j] = dp[i - 1][j];
            }
        }
    }

    if(dp[n][x]) {
        cout << "YES\n";
    }
    else {
        cout << "NO\n";
    }

    return 0;
}

