def subset_sum_exists(n, x, A):
    dp = [[0] * (x + 1) for _ in range(n + 1)]

    for i in range(n + 1):
        # Base case: can make sum = 0 always
        dp[i][0] = 1

    for j in range(1, x + 1):
        # Base case: can never make any sum with no elements
        dp[0][j] = 0

    for i in range(1, n + 1):
        for j in range(1, x + 1):
            if j >= A[i]:
                # Either can be true
                dp[i][j] = dp[i - 1][j] or dp[i - 1][j - A[i]]
            else:
                dp[i][j] = dp[i - 1][j]

    return "YES" if dp[n][x] else "NO"

