        int x = sc.nextInt();

        int[] A = new int[n + 1];

        // Using one-based indexing
        for (int i = 1; i <= n; i++) {
            A[i] = sc.nextInt();
        }

        // We will use a 2D array to store the solution
        int[][] dp = new int[n + 1][x + 1];

        for (int i = 0; i <= n; i++) {
            // Base case: can make sum = 0 always
            dp[i][0] = 1;
        }
        for (int j = 1; j <= x; j++) {
            // Base case: can never make any sum with no elements
            dp[0][j] = 0;
        }

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= x; j++) {
                if (j >= A[i]) {
                    // Either can be true
